public boolean sameEnds(int[] nums, int n) {
    int length = nums.length;

    // Check if n is within the valid range
    if (n < 0 || n > length) {
        throw new IllegalArgumentException("Invalid value of n.");
    }

    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[length - n + i]) {
            return false;
        }
    }

    return true;
}

