    if (big >= maxBigPieces) {
        goal -= maxBigPieces * 5; // Subtract the weight covered by large pieces
    } else {
        goal -= big * 5;
    }

    // Check if the remaining weight can be achieved using small chocolate pieces
    if (goal <= small) {
        return goal;
    } else {
        return -1; // Not enough small pieces to reach the goal weight
    }
}

