public boolean twoTwo(int[] nums) {
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            boolean hasAdjacentTwo = false;
            if (i > 0 && nums[i - 1] == 2) {
                hasAdjacentTwo = true;
            }
            if (i < nums.length - 1 && nums[i + 1] == 2) {
                hasAdjacentTwo = true;
            }
            if (!hasAdjacentTwo) {
                return false;
            }
        }
    }
    return true;
}

