    boolean adjacentToTwo = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            if ((i > 0 && nums[i - 1] == 2) || (i < nums.length - 1 && nums[i + 1] == 2)) {
                adjacentToTwo = true;
            } else {
                adjacentToTwo = false;
            }
        }
    }

    return adjacentToTwo;
}

