public int sum67(int[] nums) {
    boolean sixFound = false;
    int sum = 0;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 6) {
            sixFound = true;
        } else if (sixFound && nums[i] == 7) {
            sixFound = false;
        } else if (!sixFound) {
            sum += nums[i];
        }
    }

    return sum;
}

