Code:
public int[] fix45(int[] nums) {
    int i = 0;
    int j = 0;

    while (j < nums.length) {
        if (nums[j] == 4 && (j == 0 || nums[j - 1] != 5)) {
            while (nums[i] != 5 || (i > 0 && nums[i - 1] == 4)) {
                i++;
            }
            nums[i] = nums[j + 1];
            nums[j + 1] = 5;
        }
        j++;
    }

    return nums;
}

