public boolean sameEnds(int[] nums, int n) {
    // Get the length of the array
    int len = nums.length;

    // Compare the end elements of the array with the starting elements
    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[len - n + i]) {
            return false;
        }
    }

    return true;
}

