    if (isBirthday) {
        speed -= 5;
    }

    if (speed <= 60) {
        return 0; // No ticket
    } else if (speed >= 61 && speed <= 80) {
        return 1; // Small ticket
    } else {
        return 2; // Big ticket
    }
}

