Code:
public boolean sameEnds(int[] nums, int n) {
    if (n == 0) {
        return true;
    }

    int length = nums.length;
    if (n > length / 2) {
        return false;
    }

    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[length - n + i]) {
            return false;
        }
    }

    return true;
}

public int makeChocolate(int small, int big, int goal) {
  int maxBig = goal / 5;
  int numBig = Math.min(big, maxBig);
  int remaining = goal - numBig * 5;

  if (small >= remaining) {
    return remaining;
  }

  return -1;
}

