public int sum67(int[] nums) {
    boolean inSection = false;
    int sum = 0;

    for (int num : nums) {
        if (num == 6) {
            inSection = true;
        } else if (num == 7 && inSection) {
            inSection = false;
        } else if (!inSection) {
            sum += num;
        }
    }

    return sum;
}

