public boolean xyBalance(String str)
{
    int lastYIndex = -1;
    for (int i = 0; i < str.length(); i++) {
        if (str.charAt(i) == 'x') {
            lastYIndex = str.indexOf('y', lastYIndex + 1);
            if (lastYIndex == -1) {
                return false;
            }
        }
    }
    return true;
}

