public int[] fix45(int[] nums) {
    for (int i = 0, j = 0; i < nums.length; i++) {
        if (nums[i] == 4 && (i == 0 || nums[i - 1] != 5)) {
            while (nums[j] != 5 || (j > 0 && nums[j - 1] == 4)) {
