public int[] shiftLeft(int[] nums) {
    if (nums.length <= 1) {
        return nums;
    }

    int firstNum = nums[0];

    for (int i = 0; i < nums.length - 1; i++) {
        nums[i] = nums[i + 1];
    }

    nums[nums.length - 1] = firstNum;

    return nums;
}

