public int[] withoutTen(int[] nums) {
    int[] result = new int[nums.length];
    int count = 0;

    for (int num : nums) {
        if (num != 10) {
            result[count] = num;
            count++;
        }
    }

    while (count < nums.length) {
        result[count] = 0;
        count++;
    }

    return result;
}

