public int[] fix45(int[] nums) {
    int i = 0;
    for (int j = 0; j < nums.length - 1; j++) {
        if (nums[j] == 4 && nums[j + 1] != 5) {
            while (nums[i] != 5 || (i > 0 && nums[i - 1] == 4)) {
                i++;
            }
            nums[i] = nums[j + 1];
            nums[j + 1] = 5;
        }
    }
    return nums;
}

