public int caughtSpeeding(int speed, boolean isBirthday) {
    int normalLimit = 60;
    int smallTicketLimit = 80;

    if (isBirthday) {
        normalLimit += 5;
        smallTicketLimit += 5;
    }

    if (speed <= normalLimit) {
        return 0; // No ticket
    } else if (speed <= smallTicketLimit) {
        return 1; // Small ticket
    } else {
        return 2; // Big ticket
    }
}

