public int sum67(int[] nums) {
    int sum = 0;
    boolean skipSection = false;

    for (int num : nums) {
        if (num == 6) {
            skipSection = true;
            continue;
        }

        if (skipSection) {
            if (num == 7) {
                skipSection = false;
            }
            continue;
        }

        sum += num;
    }

    return sum;
}

