public boolean xyzThere(String str)
{
    for (int i = 0; i < str.length() - 2; i++) {
        if (str.charAt(i) != '.' && str.substring(i, i + 3).equals("xyz")) {
            return true;
        } else if (i > 0 && str.substring(i - 1, i + 3).equals(".xyz")) {
            return false;
        }
    }
    return false;
}

