Code:
public boolean sameEnds(int[] nums, int n) {
    // Return true if the group of n numbers at the start of the array is the same as the group of n numbers at the end of the array
    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[nums.length - n + i]) {
            return false;
        }
    }
    return true;
}

