public int sum67(int[] nums) {
    boolean inIgnoreSection = false;
    int sum = 0;

    for (int num : nums) {
        if (num == 6) {
            inIgnoreSection = true;
        } else if (num == 7 && inIgnoreSection) {
            inIgnoreSection = false;
        } else if (!inIgnoreSection) {
            sum += num;
        }
    }

    return sum;
}

