    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 4) {
            fours.add(i);
        }
    }

    for (int i = 0, j = 0; i < nums.length; i++) {
        if (nums[i] != 4 && nums[i] != 5) {
            result[j++] = nums[i];
        } else if (nums[i] == 5 && (j == 0 || result[j - 1] != 4)) {
